-- Create a demo organisation
INSERT INTO organisations (name, slug, contactEmail, createdByUserId, createdAt, updatedAt)
VALUES ('Orchid Dermatology Group', 'orchid-dermatology', 'dave@pursuitpathways.com', 1, NOW(), NOW());

-- Get the new org ID and link the facility
SET @orgId = LAST_INSERT_ID();

-- Add the platform owner as org_admin of the demo org
INSERT INTO org_members (orgId, userId, role, invitedAt, joinedAt)
VALUES (@orgId, 1, 'org_admin', NOW(), NOW());

-- Link the existing Orchid Dermatology facility to this org
UPDATE facilities SET orgId = @orgId WHERE id = 1;

-- Link the existing completed audits for that facility to this org
UPDATE audits SET orgId = @orgId WHERE facilityId = 1;

-- Link audit responses
UPDATE audit_responses SET auditId = auditId WHERE auditId IN (SELECT id FROM audits WHERE facilityId = 1);

-- Confirm
SELECT o.id, o.name, o.slug, om.role, u.name as memberName
FROM organisations o
JOIN org_members om ON om.orgId = o.id
JOIN users u ON u.id = om.userId
WHERE o.slug = 'orchid-dermatology';

